# Inputs:
# - initial_input: The initial input to the prompt chain (string)
# - solution_output: The reference solution output to compare against (string)
# - prompt_output: The output generated by the prompt chain (string)
# - eval_model: The evaluation model to use for computing accuracy (object)

# Output:
# - accuracy_score: A accuracy score between 0 and 100

"""
Genetic_algorithm_processes/S1_selection/methods/evaluation/compare_solution_eval.py
"""

import re
from Genetic_algorithm_processes.ollama_run import PromptChainRunner


class CompareSolutionEval:
    def __init__(self, eval_model: str = "qwen3:0.6b",
                 scoring_criteria: str = """
- 100: Identical or semantically equivalent
- 75-99: Minor differences, same meaning
- 50-74: Partially correct, some key information matches
- 25-49: Mostly incorrect but some relevant content
- 0-24: Completely incorrect or irrelevant""",
                 runner=PromptChainRunner(),
                 verbose: bool = False):
        self.eval_model = eval_model
        self.scoring_criteria = scoring_criteria
        self.runner = runner
        self.verbose = verbose

    def evaluate(self, prompt_output: str, eval_context: dict) -> float:
        eval_prompt = f"""You are an objective evaluator. Compare the PROMPT OUTPUT against the REFERENCE OUTPUT for the given INPUT, and return a single integer score from 0 to 100 representing how accurate and semantically similar the prompt output is to the reference output.

INPUT:
{eval_context["initial_input"]}

REFERENCE OUTPUT:
{eval_context["solution_output"]}

PROMPT OUTPUT:
{prompt_output}

Scoring criteria:
{self.scoring_criteria}

Respond with ONLY a single integer between 0 and 100. No explanation, no punctuation, just the number."""

        output, _ = self.runner.run_ollama_model(self.eval_model, eval_prompt)

        score = self._parse_score(output)

        if self.verbose:
            status = "✅" if score >= 75 else "⚠️" if score >= 50 else "❌"
            print(f"\n{'─'*40}")
            print(f"  {status}  Evaluation complete")
            print(f"      Model   : {self.eval_model}")
            print(f"      Input   : {eval_context['initial_input'][:60]!r}")
            print(f"      Expected: {eval_context['solution_output'][:60]!r}")
            print(f"      Got     : {prompt_output[:60]!r}")
            print(f"      Score   : {score:.0f}/100")
            print(f"{'─'*40}\n")

        return score

    def _parse_score(self, model_output: str) -> float:
        cleaned = model_output.strip()

        if self.verbose:
            print(f"[CompareSolutionEval] Raw model output: {cleaned!r}")

        # Happy path: output is strictly a number
        if re.fullmatch(r'\d{1,3}', cleaned):
            return max(0.0, min(100.0, float(cleaned)))

        # Best-guess: take the last number found (models tend to conclude with their answer)
        matches = re.findall(r'\b(\d{1,3})\b', cleaned)
        if matches:
            print(f"[CompareSolutionEval] ⚠️  Model didn't follow instructions — best-guess extraction (last number): {matches[-1]}")
            return max(0.0, min(100.0, float(matches[-1])))

        print(f"[CompareSolutionEval] ⚠️  Could not parse score from: {cleaned!r} — defaulting to 0.0")
        return 0.0


if __name__ == "__main__":
    evaluator = CompareSolutionEval(eval_model="qwen3:0.6b")

    eval_context = {
        "initial_input": "What was the capital of Russia?",
        "solution_output": "St. Petersburg was the capital of Russia",
    }
    score = evaluator.evaluate("St. Petersburg was the capital of Russia from 1712 to 1918, and Moscow became the capital in 1918.", eval_context)
    print(f"Final Score: {score:.1f}/100")